function calcGames(board,qty){
  if(!qty||qty<0) return {paid:0,free:0,total:0,cost:0};
  const free=Math.floor(qty/board.freeEvery)*board.freeCount;
  return {paid:qty,free,total:qty+free,cost:qty*board.pricePerGame};
}

// #2 — Phone validation
function isValidPhone(p){ return /^0[7-9][0-1]\d{8}$/.test(p.replace(/\s/g,"")); }

// #3 — Date validation
function isValidDate(d){
  if(!d) return false;
  const today=new Date(); today.setHours(0,0,0,0);
  return new Date(d)>=today;
}

function BoardCard({board,qty,onChange}){
  const {paid,free,total,cost}=calcGames(board,qty);
  const remainder=qty%board.freeEvery;
  const nextFreeIn=(remainder===0)?board.freeEvery:board.freeEvery-remainder;
  const showHint=qty>0&&remainder!==0;
  const isActive=qty>0;
  return(
    <div className={`board-card ${isActive?board.activeClass:""}`}>
      {isActive&&<div className="active-check"><FaCheck /></div>}
      <div className={board.headerClass}>
        <div className="board-icon"><BoardIcon type={board.icon} /></div>
        <div className={`board-name ${board.nameClass}`}>{board.name}</div>
        <div className="board-tagline">{board.tagline}</div>
      </div>
      <div className="board-body">
        <div className="price-row">
          <div className="price-amt">₦{board.pricePerGame.toLocaleString()}</div>
          <div className="price-unit">per game / coin</div>
        </div>
        <div className={`promo-badge ${board.promoClass}`}>
          <FaTrophy style={iconStyle} /> {board.freeCount} free game{board.freeCount>1?"s":""} every {board.freeEvery} ordered
        </div>
        <div className="gc-label">Games to order</div>
        <div className="gc-controls">
          <button className="gc-btn" onClick={()=>onChange(Math.max(0,qty-1))}>−</button>
          <div><div className="gc-count">{qty}</div><div className="gc-unit">game{qty!==1?"s":""}</div></div>
          <button className="gc-btn" onClick={()=>onChange(qty+1)}>+</button>
        </div>
        {qty>0&&(
          <div className="gc-breakdown">
            <div className="gc-row"><span className="lbl">Paid games</span><span className="val">{paid}</span></div>
            <div className="gc-row"><span className="lbl">Free games</span><span className={`val ${free>0?"gc-free":""}`}>{free>0?`+${free} FREE 🎉`:"—"}</span></div>
            <div className="gc-row"><span className="lbl">Total to play</span><span className="val">{total} game{total!==1?"s":""}</span></div>
            {showHint&&<div className="gc-hint">+{nextFreeIn} more → unlock next {board.freeCount} free 🎁</div>}
            <div className="gc-total-row"><span className="gc-total-lbl">You pay</span><span className="gc-total-amt">₦{cost.toLocaleString()}</span></div>
          </div>
        )}
      </div>
    </div>
  );
}

